import{_ as o,o as t,c as d,a3 as c}from"./chunks/framework.BlfGB29P.js";const u=JSON.parse('{"title":"身份与认证","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/identity.md","filePath":"cosmos/basic-app/identity.md","lastUpdated":1783773945000}'),a={name:"cosmos/basic-app/identity.md"};function s(n,e,r,i,l,p){return t(),d("div",null,[...e[0]||(e[0]=[c(`<h1 id="身份与认证" tabindex="-1">身份与认证 <a class="header-anchor" href="#身份与认证" aria-label="Permalink to &quot;身份与认证&quot;">​</a></h1><p>XiHan.BasicApp 的身份体系围绕<strong>统一身份</strong>设计：一个自然人对应一个 <code>SysUser</code> 账号，用<strong>邮箱</strong>作为全平台唯一登录标识；同一账号可通过成员关系在多个租户里办事。本页讲清楚<strong>主体模型</strong>（用户/角色/部门/菜单/岗位）、<strong>登录方式</strong>、<strong>令牌与会话</strong>、<strong>密码安全</strong>、<strong>登录落点</strong>与<strong>个人中心</strong>。</p><blockquote><p>权限如何判定（权限码、数据范围、字段脱敏、ABAC）见 <a href="./permissions">权限模型</a>；租户隔离、成员关系、版本门控见 <a href="./multi-tenancy">多租户</a>。本页只做交叉链接，不重复。</p></blockquote><h2 id="主体模型" tabindex="-1">主体模型 <a class="header-anchor" href="#主体模型" aria-label="Permalink to &quot;主体模型&quot;">​</a></h2><p>RBAC 的核心实体都落在 <code>Saas</code> 模块的 <code>Domain/Entities</code> 下，均为 <code>snake_case</code> 表、软删、带 <code>TenantId</code>：</p><table tabindex="0"><thead><tr><th>实体</th><th>表</th><th>职责</th></tr></thead><tbody><tr><td><code>SysUser</code></td><td><code>Sys_User</code></td><td>身份主体（Subject）：用户名/邮箱/手机/资料。<code>Email</code> 全平台唯一（<code>UX_Em</code>），是登录标识</td></tr><tr><td><code>SysUserSecurity</code></td><td><code>Sys_User_Security</code></td><td>与 <code>SysUser</code> 一对一的<strong>安全扩展</strong>：密码哈希、锁定、MFA、失败计数、多端策略</td></tr><tr><td><code>SysRole</code></td><td><code>Sys_Role</code></td><td>角色：一组权限的分配单元，支持层级继承与数据范围</td></tr><tr><td><code>SysDepartment</code></td><td><code>Sys_Department</code></td><td>组织架构树节点（单父严格树），是数据范围 <code>dept</code>/<code>dept_and_sub</code> 的基础</td></tr><tr><td><code>SysDepartmentHierarchy</code></td><td><code>Sys_Department_Hierarchy</code></td><td>部门层级<strong>闭包表</strong>：预计算祖先-后代对，支持 O(1) 展开</td></tr><tr><td><code>SysMenu</code></td><td><code>Sys_Menu</code></td><td>纯 UI 结构（导航/路由/展示），通过 <code>PermissionId</code> 绑定一个权限点</td></tr><tr><td><code>SysPosition</code></td><td><code>Sys_Position</code></td><td>扁平岗位字典（职务/职位），供人员任用引用</td></tr><tr><td><code>SysExternalLogin</code></td><td><code>Sys_External_Login</code></td><td>本地用户与第三方身份（github/google/qq…）的绑定关系</td></tr><tr><td><code>SysUserSession</code></td><td><code>Sys_User_Session</code></td><td>会话中心：登录状态、多端控制、设备信息、撤销</td></tr><tr><td><code>SysLoginLog</code></td><td><code>Sys_Login_Log_{按月分表}</code></td><td>登录/认证审计（含成功与失败），按月分表</td></tr></tbody></table><p>关系（关联表）：</p><ul><li>用户 ↔ 角色：<code>SysUserRole</code>（<code>Sys_User_Role</code>），多对多、支持带生效期的临时授权（<code>EffectiveTime</code>/<code>ExpirationTime</code>）。</li><li>用户 ↔ 部门：<code>SysUserDepartment</code>（<code>Sys_User_Department</code>），多部门归属，<code>IsMain</code> 标识主部门，可挂 <code>PositionId</code>（岗位）、工号、职级、入职日期。</li><li>角色 ↔ 权限、角色继承、数据范围等归权限模型，见 <a href="./permissions">权限模型</a>。</li></ul><h3 id="用户-sysuser" tabindex="-1">用户（SysUser） <a class="header-anchor" href="#用户-sysuser" aria-label="Permalink to &quot;用户（SysUser）&quot;">​</a></h3><p>一条重要语义澄清：<code>SysUser.TenantId</code> 是用户的<strong>主账号归属租户</strong>（注册地），<strong>不等同于</strong>&quot;能进入哪个租户&quot;——后者由多租户的成员关系（<code>SysTenantUser</code>）承载。因此：</p><ul><li><code>TenantId + UserName</code> 在主归属租户内唯一；<code>Email</code> <strong>全平台唯一</strong>（可空，有值必唯一）。</li><li><code>Status</code>（启用/禁用）与 <code>IsActive</code>（是否激活，邮箱/手机验证）<strong>正交</strong>：未激活或被禁用都不可登录。</li><li><code>IsSystemAccount=true</code> 的内置账号禁止改用户名、禁止软删。</li><li>平台账号约定 <code>TenantId=0</code>（如超管），恒落平台运维态。</li><li>用户级数据范围可用 <code>DataScopeOverride</code> 覆盖角色默认（细节见权限模型）。</li></ul><p>敏感安全字段刻意拆到一对一的 <code>SysUserSecurity</code>（<code>Password</code>/<code>TwoFactorSecret</code>/<code>SecurityStamp</code> 均 <code>[JsonIgnore]</code>，不出接口），避免污染用户主表、便于单独脱敏与访问控制。</p><h3 id="部门与闭包表" tabindex="-1">部门与闭包表 <a class="header-anchor" href="#部门与闭包表" aria-label="Permalink to &quot;部门与闭包表&quot;">​</a></h3><p>部门是严格单父树。为了高效回答&quot;某部门的全部下级/祖先&quot;（数据范围 <code>dept_and_sub</code> 要用），系统用<strong>闭包表</strong> <code>SysDepartmentHierarchy</code> 把所有&quot;祖先-后代对&quot;预计算出来（含 <code>Depth=0</code> 的自环），并冗余 <code>Path</code>/<code>PathName</code> 便于面包屑。</p><p>闭包表是&quot;查询加速镜像&quot;，不是独立业务数据——所有写入必须由 <code>SysDepartment</code> 变更触发，服务层在<strong>增/删/移</strong>部门时统一重建：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新增部门 N 挂在父 P 下：</span></span>
<span class="line"><span>  INSERT SELECT AncestorId, N, Depth+1 FROM 闭包 WHERE DescendantId = P</span></span>
<span class="line"><span>  再补 (N, N, 0)</span></span>
<span class="line"><span>移动子树：先删旧闭包，再按新父重建</span></span>
<span class="line"><span>删除部门 N：DELETE WHERE DescendantId = N OR AncestorId = N</span></span></code></pre></div><h3 id="菜单" tabindex="-1">菜单 <a class="header-anchor" href="#菜单" aria-label="Permalink to &quot;菜单&quot;">​</a></h3><p><code>SysMenu</code> 只描述 UI 层级（目录/菜单/按钮/外链），<strong>后端鉴权永远基于 Permission，不依赖菜单存在性</strong>。菜单通过可空的 <code>PermissionId</code> 反向绑定一个权限点：空=纯展示菜单；有值=按该权限码门控可见性。若一个菜单需要多个权限，约定<strong>建组合权限点</strong>再绑定，而非引多对多。</p><blockquote><p>运行时的菜单/路由/组件路径/权限码/国际化键由后端 <code>PageRegistry</code> 作为单一事实源统一注册（见 <a href="./architecture">系统架构</a>）；<code>SysMenu</code> 表是其落库形态。<code>TenantId=0</code> 为平台全局菜单，所有租户共享读取，租户可叠加私有菜单。</p></blockquote><h2 id="登录方式" tabindex="-1">登录方式 <a class="header-anchor" href="#登录方式" aria-label="Permalink to &quot;登录方式&quot;">​</a></h2><p>登录入口是 <code>AuthAppService</code>（<code>[DynamicApi(RouteTemplate = &quot;api/Auth&quot;)]</code>）。核心设计是<strong>先登录后选租户</strong>：登录页不选租户，统一在<strong>平台态</strong>（<code>TenantId=null</code>）完成身份认证，认证通过后再按成员关系决定落点（见下文&quot;登录落点&quot;）。</p><p>前端先调 <code>GET /api/Auth/GetLoginConfig</code> 拿到 <code>LoginConfigDto</code>（<code>LoginMethods</code> + <code>OAuthProviders</code>），据此决定展示哪些登录按钮——<strong>支持的方式以该配置为准</strong>。</p><h3 id="账号密码" tabindex="-1">账号密码 <a class="header-anchor" href="#账号密码" aria-label="Permalink to &quot;账号密码&quot;">​</a></h3><p><code>POST /api/Auth/Login</code>（<code>LoginRequestDto</code>）。<code>Username</code> 传邮箱（全平台唯一定位）；平台账号也可用用户名。流程：</p><ol><li>平台态定位账号 → <code>IAuthenticationDomainService.AuthenticatePasswordLoginAsync</code>：校验存在性、<code>IsActive</code>、密码哈希、账户锁定/失败计数，并判定是否需要二次验证。</li><li>应用层附加校验：<code>Status</code> 是否启用、（带租户时）成员关系与生效/过期、密码是否过期。</li><li>若 <code>RequiresTwoFactor</code> → 返回 2FA 挑战（不签发令牌，见下）。</li><li>通过 → 决定落点租户、签发双令牌、落地会话、发布登录成功领域事件。</li></ol><p>失败会发布 <code>AuthLoginFailedDomainEvent</code>（落 <code>SysLoginLog</code>），并抛出友好错误。</p><h3 id="邮箱验证码" tabindex="-1">邮箱验证码 <a class="header-anchor" href="#邮箱验证码" aria-label="Permalink to &quot;邮箱验证码&quot;">​</a></h3><p>两步，均匿名：</p><ol><li><code>POST /api/Auth/EmailLoginCode</code>（<code>EmailLoginCodeRequestDto</code>）：邮箱+IP 频率限制（60s 窗口）→ 复用邮箱登录的账号可用性校验 → 下发验证码。</li><li><code>POST /api/Auth/EmailLogin</code>（<code>EmailLoginRequestDto</code>）：一次性消费验证码 → 校验账号 → 签发令牌并落点。</li></ol><p>验证码为 <strong>6 位数字、有效期 10 分钟（600s）、一次性消费</strong>（读取即销毁，无论成败），由框架 <code>IOneTimeCodeService</code> 存分布式缓存承载。开发环境会在结果里回显 <code>DebugCode</code> 便于联调，生产绝不回显。</p><h3 id="第三方登录-oauth2" tabindex="-1">第三方登录（OAuth2） <a class="header-anchor" href="#第三方登录-oauth2" aria-label="Permalink to &quot;第三方登录（OAuth2）&quot;">​</a></h3><p>内建支持 <strong>GitHub / Google / QQ</strong>（可扩展），由框架 <code>XiHan.Framework.Authentication.OAuth</code> 提供，配置节 <code>XiHan:Authentication:OAuth</code>（<code>OAuthOptions</code>：<code>Enabled</code>/<code>FrontendCallbackUrl</code>/<code>Providers[]</code>）。前端登录页展示哪些提供商由运行时配置 <code>saas.auth.oauth.providers</code>（存库）决定。</p><p>OAuth 走<strong>独立的 Web 端点</strong>（不是动态 API），落在 <code>Infrastructure/OAuth/OAuthEndpoints.cs</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 前端跳转：GET /api/OAuth/ExternalLogin?provider=github[&amp;bindTicket=xxx]</span></span>
<span class="line"><span>      端点校验 provider（绑定意图则一次性消费 bindTicket 得到 userId）</span></span>
<span class="line"><span>      → ChallengeAsync(provider) → 302 到 GitHub/Google/QQ 授权页</span></span>
<span class="line"><span>② 用户在三方授权</span></span>
<span class="line"><span>③ 三方回跳：GET /api/OAuth/Callback?code=...&amp;state=...</span></span>
<span class="line"><span>      端点 AuthenticateAsync(ExternalCookie) 读出三方 Claim：</span></span>
<span class="line"><span>        NameIdentifier → providerKey、Email、Name → displayName、统一头像 Claim → avatar</span></span>
<span class="line"><span>      → 调 IAuthAppService.ExternalLoginAsync(...)   （见下方&quot;注意&quot;）</span></span>
<span class="line"><span>      → 302 回 FrontendCallbackUrl，成功时带 accessToken/refreshToken/expiresIn</span></span></code></pre></div><p><code>ExternalLoginAsync</code> 被标 <code>[DynamicApi(IsEnabled = false)]</code>（不对外暴露），只由回调端点内部调用；且调用时用 <code>ProxyHelper.UnProxy</code> 取真实目标实例——因为匿名端点没有 UoW 中间件，走 Castle 代理会让拦截器急切开事务而死锁。</p><p>登录/建号规则（<code>LoginByExternalAsync</code>）：</p><ul><li>按 <code>(Provider, ProviderKey, TenantId)</code> <strong>精确</strong>定位用户（唯一约束 <code>UX_Pr_PrKe_TeId</code>）。</li><li>未绑定则<strong>首登自动建号</strong>：用户名 <code>{provider}_{随机hex}</code>、随机强密码、不分配角色；三方邮箱<strong>仅在未被占用时</strong>采用，否则用占位邮箱 <code>{username}@external.local</code>——<strong>绝不按邮箱并入既有账号</strong>（防冒用）。</li><li><code>SysExternalLogin</code> 只存身份关联（Provider/ProviderKey/邮箱/头像），<strong>不存三方 Access/Refresh Token</strong>。</li></ul><p><strong>账号绑定</strong>（把三方账号绑到已登录用户）：已登录用户先 <code>POST /api/Auth/CreateOAuthBindTicket</code> 拿一次性票据（<code>oauth:bind-ticket:{ticket}</code>，缓存 5 分钟），带 <code>bindTicket</code> 走同一发起端点；回调时以 <code>IsBind=true</code> 走 <code>BindExternalLoginAsync</code>，已被他人绑定则拒绝（<code>conflict</code>）。</p><blockquote><p>具体支持哪些 provider、scope、回调地址以仓库配置为准。</p></blockquote><h3 id="两步验证-2fa-mfa" tabindex="-1">两步验证（2FA / MFA） <a class="header-anchor" href="#两步验证-2fa-mfa" aria-label="Permalink to &quot;两步验证（2FA / MFA）&quot;">​</a></h3><p><code>SysUserSecurity.TwoFactorMethod</code> 是 <code>[Flags]</code> 枚举，可同时启用多种：</p><table tabindex="0"><thead><tr><th>方式</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td><code>None</code></td><td>0</td><td>未启用</td></tr><tr><td><code>Totp</code></td><td>1</td><td>认证器 App（Google/Microsoft Authenticator 等）</td></tr><tr><td><code>Email</code></td><td>2</td><td>邮箱验证码</td></tr><tr><td><code>Phone</code></td><td>4</td><td>短信验证码（要求已绑定且已验证手机号，否则不对外公布）</td></tr></tbody></table><p>当密码/邮箱登录判定 <code>RequiresTwoFactor</code>：</p><ol><li>未提交验证码 → 返回 <code>LoginResponseDto { RequiresTwoFactor=true, AvailableTwoFactorMethods, TwoFactorMethod, CodeSent }</code>；对 email/phone 方式会<strong>先下发验证码</strong>（TOTP 由认证器本地生成，无需下发）。</li><li>提交验证码 → 按方式校验：<code>totp</code> 走 <code>IOtpService.VerifyTotpCode</code>；<code>email</code> 走一次性验证码消费；<code>phone</code> 走个人中心验证服务消费。校验失败发布失败事件并抛错。</li><li>通过 → 继续签发令牌。</li></ol><p>TOTP 遵循 RFC 6238：HMAC-SHA1、Base32 密钥、6 位、30 秒步长、±1 窗口容差；provisioning URI 形如 <code>otpauth://totp/{issuer}:{account}?secret=...&amp;period=30&amp;digits=6</code>。用户在<a href="#个人中心">个人中心</a>开启/关闭各方式。</p><h2 id="令牌与会话" tabindex="-1">令牌与会话 <a class="header-anchor" href="#令牌与会话" aria-label="Permalink to &quot;令牌与会话&quot;">​</a></h2><h3 id="jwt-双令牌" tabindex="-1">JWT 双令牌 <a class="header-anchor" href="#jwt-双令牌" aria-label="Permalink to &quot;JWT 双令牌&quot;">​</a></h3><p>登录成功签发 <code>LoginTokenDto</code>：<strong>Access Token</strong>（JWT，HMAC-SHA256 签名）+ <strong>Refresh Token</strong>（不透明随机串）。配置节 <code>XiHan:Authentication:Jwt</code>（<code>JwtOptions</code>），默认 Access 60 分钟、Refresh 7 天、时钟偏移容差 5 分钟（<strong>以仓库配置为准</strong>）。</p><p>Access Token 的 Claim 主要有：<code>sub</code>/<code>jti</code>、<code>UserId</code>、<code>UserName</code>、<code>SessionId</code>、<code>TenantId</code>（有则带）、<code>Email</code>/<code>Phone</code>/<code>Picture</code>、<code>DeviceFingerprint</code>、多个 <code>Role</code>。<strong>具体权限码不冻结进令牌</strong>——只在超管时放一个通配 <code>*</code> 作快路径；其余权限一律由服务端<strong>实时快照</strong>判定，避免授予/回收后令牌失效不及时，也避免权限清单泄露（与 <a href="./permissions">权限模型</a> 的实时校验一致）。</p><p>刷新：<code>POST /api/Auth/RefreshToken</code>（<code>RefreshTokenRequestDto</code> 带旧 AccessToken + RefreshToken）→ 校验后签发新令牌，并落一条 <code>TokenRefreshed</code> 审计。</p><h3 id="会话与多端登录" tabindex="-1">会话与多端登录 <a class="header-anchor" href="#会话与多端登录" aria-label="Permalink to &quot;会话与多端登录&quot;">​</a></h3><p>每次登录写一条 <code>SysUserSession</code>（会话中心）：记录 <code>UserSessionId</code>（业务会话号）、<code>CurrentAccessTokenJti</code>（只存 JTI 不存完整 Token，便于黑名单/撤销）、设备类型/名称/指纹、浏览器/OS/IP/位置、登录与最后活动时间、<code>ExpirationTime</code>。会话状态 <code>SessionStatus</code>：</p><table tabindex="0"><thead><tr><th>状态</th><th>值</th><th>含义</th></tr></thead><tbody><tr><td><code>Active</code></td><td>0</td><td>活跃（鉴权&quot;会话有效&quot;= <code>Active</code> 且未软删）</td></tr><tr><td><code>Offline</code></td><td>1</td><td>登出/心跳超时</td></tr><tr><td><code>Revoked</code></td><td>2</td><td>强制下线/安全撤销</td></tr><tr><td><code>Expired</code></td><td>3</td><td>超过绝对过期时间</td></tr></tbody></table><p>多端策略由 <code>SysUserSecurity</code> 控制：<code>AllowMultiLogin</code>（是否允许多端，默认 true）与 <code>MaxLoginDevices</code>（最大设备数，0=不限）。同一自然人在不同租户可复用同一业务 <code>SessionId</code>，但会落成<strong>不同 TenantId 的独立会话记录</strong>。</p><p>登出 <code>POST /api/Auth/Logout</code>：按 <code>userId + SessionId</code> 撤销会话、吊销关联令牌，并发布登出领域事件。用户自助的&quot;我的设备/会话&quot;管理、踢其他端，见<a href="#个人中心">个人中心</a>；管理员侧撤销走 <code>UserSessionAppService</code>（需 <code>SysPermissionCodes.UserSession.Revoke</code> 权限）。删除用户时会吊销其全部会话并实时 <code>ForceLogout</code> 踢出在线连接。</p><h2 id="密码安全" tabindex="-1">密码安全 <a class="header-anchor" href="#密码安全" aria-label="Permalink to &quot;密码安全&quot;">​</a></h2><ul><li><p><strong>哈希算法：PBKDF2</strong>（框架 <code>XiHan.Framework.Security.Password.PasswordHasher</code>，配置节 <code>XiHan:Authentication:PasswordHasher</code>）。默认 <strong>HMAC-SHA256、迭代 600,000 次（OWASP 建议）、32 字节随机盐、32 字节输出</strong>；存储格式为自描述串 <code>version:iterations:algorithm:base64(salt):base64(hash)</code>，校验用定长比较（抗时序攻击），参数变更时 <code>NeedsRehash</code> 支持透明升级。密码<strong>严禁明文落库</strong>（<code>SysUserSecurity.Password</code>，<code>[JsonIgnore]</code>）。</p><blockquote><p>部分实体注释写的是&quot;Argon2/BCrypt&quot;，那是历史注释；<strong>当前实现是 PBKDF2</strong>，以仓库源码为准。</p></blockquote></li><li><p><strong>验证码一次性消费</strong>：邮箱登录码、2FA 邮箱/短信码、找回密码链接均<strong>用后即焚</strong>——读取即从缓存删除，防重放/爆破。邮箱码 6 位、10 分钟；找回密码令牌 30 分钟。</p></li><li><p><strong>找回密码</strong>（匿名，防用户枚举）：<code>POST /api/Auth/PasswordResetRequest</code> 无论邮箱是否存在都返回&quot;已受理&quot;；存在则签发一次性重置令牌（<code>auth:pwd-reset:{token}</code>，缓存 30 分钟，仅记录 token→userId，<strong>不立即改密</strong>）并邮件带链接。用户点链接后 <code>POST /api/Auth/ConsumePasswordResetToken</code> 设新密码（8-128 位），成功即失效令牌并落 <code>PasswordReset</code> 审计。</p></li><li><p><strong>锁定与风控</strong>：<code>SysUserSecurity</code> 记 <code>FailedLoginAttempts</code>/<code>LockoutEndTime</code> 等；<code>SysLoginLog</code> 记录每次尝试（含 <code>IsRiskLogin</code> 异地/新设备标记），按月分表，供暴力破解检测与合规审计。</p></li><li><p><strong>注册</strong>（<code>POST /api/Auth/Register</code>，匿名）：邮箱必填（全平台唯一登录标识），统一落默认注册租户、成为普通成员、<strong>不分配角色</strong>（权限由管理员后续授权）；欢迎邮件尽力而为、失败不阻断。</p></li></ul><h2 id="登录落点" tabindex="-1">登录落点 <a class="header-anchor" href="#登录落点" aria-label="Permalink to &quot;登录落点&quot;">​</a></h2><p>&quot;先登录后选租户&quot;下，认证通过后由 <code>ResolveLoginLandingAsync</code> 决定进入哪里（进入后可随时 <code>POST /api/Auth/SwitchTenant</code> 切换）：</p><table tabindex="0"><thead><tr><th>归属情况</th><th>落点</th></tr></thead><tbody><tr><td>平台账号（<code>TenantId=0</code>）或超管角色</td><td><strong>平台态</strong>（控制中心：管理租户/用户/系统，或选租户进入）</td></tr><tr><td>恰好一个可用租户成员</td><td><strong>直接进入该租户</strong>（免选择）</td></tr><tr><td>零个或多个可用租户</td><td><strong>平台态</strong>（前端展示选择/原因）</td></tr></tbody></table><p>签发的令牌是否带 <code>TenantId</code> claim 随落点而定（平台态不带）。<code>GetUserInfo</code> 返回的 <code>UserInfoDto</code> 带 <code>IsPlatform</code>/<code>CanAccessPlatform</code> 供前端判断。切换到具体租户时会校验成员身份（超管可进任意租户）并在目标上下文重建授权快照。落点/切换与多租户强相关，成员关系、平台运维态、版本门控详见 <a href="./multi-tenancy">多租户</a>。</p><h2 id="个人中心" tabindex="-1">个人中心 <a class="header-anchor" href="#个人中心" aria-label="Permalink to &quot;个人中心&quot;">​</a></h2><p><code>ProfileAppService</code>（<code>[DynamicApi(RouteTemplate 前缀 api/Profile)]</code>，<code>[Authorize]</code>）覆盖当前登录用户的自助管理，拆成多个 partial：</p><ul><li><strong>资料</strong>：<code>GetProfile</code> / <code>UpdateProfile</code>（昵称、头像、性别、时区、语言等）；改用户名 <code>ChangeUserName</code>（内置账号禁改，改后通知）。</li><li><strong>安全 · 密码</strong>：<code>ChangePassword</code>（域服务校验旧密码，改后落 <code>PasswordChanged</code> 审计并通知）。</li><li><strong>安全 · 2FA</strong>：TOTP 用 <code>Setup2FA</code>（返回 <code>SharedKey</code> + <code>AuthenticatorUri</code> 供扫码）→ <code>Enable2FA</code>（提交验证码激活）；<code>Disable2FA</code> 关闭；email/phone 方式用 <code>Send2FASetupCode</code> 先下发再 <code>Enable2FA</code>。绑定/解绑落 <code>MfaBound</code>/<code>MfaUnbound</code> 审计。</li><li><strong>联系方式换绑/验证</strong>：换邮箱/手机走&quot;发码→确认&quot;两步（<code>ProfileVerificationPurpose</code> 区分用途：<code>ChangeEmail</code>/<code>ChangePhone</code>/<code>VerifyEmail</code>/<code>VerifyPhone</code>/<code>TwoFactorEmail</code>/<code>TwoFactorPhone</code>），需密码确认、校验唯一性。</li><li><strong>会话/设备</strong>：<code>GetSessions</code> 列出本人在线会话（标出当前会话）；<code>RevokeSession</code> 撤销指定设备；<code>RevokeOtherSessions</code> 一键踢掉其他所有端；<code>GetLoginLogs</code> 查本人登录历史。</li><li><strong>第三方账号</strong>：<code>GetLinkedAccounts</code> 列出已绑定的三方账号；<code>UnlinkAccount</code> 解绑（解绑前防止失去唯一登录方式）。</li><li><strong>开发者 · API 凭证</strong>（<code>SysUserApiCredential</code>）：<code>GetApiCredentials</code> 列出本人凭证；<code>CreateApiCredential</code>/<code>RotateApiCredentialSecret</code> 生成/滚动 <code>AppKey</code>（<code>ak_</code> 前缀，全局唯一）+ <code>AppSecret</code>（<code>sk_</code> 前缀，与账号密码同栈 <code>IPasswordHasher</code> 只存哈希，明文仅创建/滚动时返回一次）；<code>UpdateApiCredentialStatus</code>/<code>DeleteApiCredential</code> 启停/删除；每用户最多 5 个凭证，供服务端签名调用 OpenAPI，变更均触发安全通知。</li><li><strong>偏好</strong>：通知偏好 <code>GetNotificationPreference</code>/<code>UpdateNotificationPreference</code>（渠道 × 类型开关）；UI 偏好走 <code>UserSettingAppService</code> 按场景（Scene）+ key 存取，保存后经 SignalR 广播实现<strong>多端同步</strong>（服务端不解释 value，仅作跨端状态载体）。</li><li><strong>账号注销</strong>：<code>DeactivateAccount</code>（停用）/<code>DeleteAccount</code>（软删，<code>[HttpPost]</code> 显式锁定），均需密码确认并撤销全部会话。</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="./permissions">权限模型</a>：权限码、RBAC 继承、数据范围、字段脱敏、ABAC 约束、实时校验。</li><li><a href="./multi-tenancy">多租户</a>：成员关系、平台运维态、租户切换、版本门控。</li><li><a href="./../framework/packages/authentication">框架 · 认证模块</a>：JWT / OAuth2 / TOTP / PBKDF2 的底层实现。</li><li><a href="./architecture">系统架构</a>：认证/租户解析/授权在请求管道中的位置，与后端驱动菜单。</li></ul>`,66)])])}const g=o(a,[["render",s]]);export{u as __pageData,g as default};
